+        list.select(invalid);
+        assertEquals(-1, list.getSelectedIndex());
+        assertEquals(3, list.getSelectedIndexes().length);
+        assertTrue(list.isIndexSelected(0));
+        assertTrue(list.isIndexSelected(1));
+        assertTrue(list.isIndexSelected(2));
+
+        list.deselect(0);
+        list.select(invalid);
+        assertEquals(-1, list.getSelectedIndex());
+        assertEquals(3, list.getSelectedIndexes().length);
+        assertTrue(list.isIndexSelected(0));
+        assertTrue(list.isIndexSelected(1));
+        assertTrue(list.isIndexSelected(2));
+    }
+
